/* ── Heat Gauge (CSS arc) ── */
function HeatGauge({ value, label }) {
  const pct = Math.min(Math.max(value, 0), 100)
  const angle = -90 + (pct / 100) * 180
  const gaugeColor = pct < 30 ? T.green : pct < 60 ? T.amber : T.red
  return (
    <div style={{ textAlign: 'center' }}>
      <div style={{ position: 'relative', width: 140, height: 80, margin: '0 auto' }}>
        {/* Background arc */}
        <svg viewBox="0 0 140 80" style={{ width: 140, height: 80 }}>
          <path d="M10,75 A60,60 0 0,1 130,75" fill="none" stroke={T.border} strokeWidth="10" strokeLinecap="round" />
          <path d="M10,75 A60,60 0 0,1 130,75" fill="none"
            stroke={`url(#heatGrad)`} strokeWidth="10" strokeLinecap="round"
            strokeDasharray={`${pct * 1.88} 188`}
          />
          <defs>
            <linearGradient id="heatGrad" x1="0" y1="0" x2="1" y2="0">
              <stop offset="0%" stopColor={T.green} />
              <stop offset="50%" stopColor={T.amber} />
              <stop offset="100%" stopColor={T.red} />
            </linearGradient>
          </defs>
        </svg>
        {/* Needle */}
        <div style={{
          position: 'absolute', bottom: 5, left: '50%',
          width: 2, height: 40, background: gaugeColor,
          transformOrigin: 'bottom center',
          transform: `translateX(-50%) rotate(${angle}deg)`,
          borderRadius: 6, boxShadow: `0 0 8px ${gaugeColor}66`,
        }} />
        <div style={{
          position: 'absolute', bottom: 0, left: '50%', transform: 'translateX(-50%)',
          width: 8, height: 8, borderRadius: '50%', background: gaugeColor,
        }} />
      </div>
      <div style={{ fontFamily: T.monoFont, fontSize: 22, fontWeight: 800, color: gaugeColor, marginTop: 8 }}>{pct}%</div>
      <div style={{ fontSize: 11, color: T.textSecondary, fontWeight: 600, marginTop: 4 }}>{label}</div>
    </div>
  )
}

