/* ── Correlation Mini Grid ── */
function CorrelationGrid() {
  const labels = ['US', 'EU', 'Crypto']
  const data = [
    [1.0, 0.72, 0.31],
    [0.72, 1.0, 0.18],
    [0.31, 0.18, 1.0],
  ]
  function corrColor(v) {
    if (v >= 0.8) return T.red + '88'
    if (v >= 0.5) return T.amber + '66'
    return T.green + '44'
  }
  return (
    <div>
      <div style={{ fontSize: 10, color: T.textSecondary, fontWeight: 700, textTransform: 'uppercase', marginBottom: 8 }}>Correlation Matrix</div>
      <div style={{ display: 'grid', gridTemplateColumns: '40px repeat(3, 1fr)', gap: 4 }}>
        <div />
        {labels.map(l => <div key={l} style={{ fontSize: 10, color: T.textSecondary, textAlign: 'center', fontFamily: T.monoFont }}>{l}</div>)}
        {data.map((row, i) => (
          <>
            <div key={`label-${i}`} style={{ fontSize: 10, color: T.textSecondary, display: 'flex', alignItems: 'center', fontFamily: T.monoFont }}>{labels[i]}</div>
            {row.map((v, j) => (
              <div key={`${i}-${j}`} style={{
                background: corrColor(v), borderRadius: 6, padding: '6px 4px',
                textAlign: 'center', fontFamily: T.monoFont, fontSize: 10, fontWeight: 600, color: T.textPrimary,
              }}>{v.toFixed(2)}</div>
            ))}
          </>
        ))}
      </div>
    </div>
  )
}

